import{_ as e,o as a,c as r,ag as i}from"./chunks/framework.DAY4Zhxq.js";const g=JSON.parse('{"title":"Chat","description":"","frontmatter":{},"headers":[],"relativePath":"guide/chat.md","filePath":"guide/chat.md"}'),o={name:"guide/chat.md"};function n(d,t,s,h,l,c){return a(),r("div",null,[...t[0]||(t[0]=[i('<h1 id="chat" tabindex="-1">Chat <a class="header-anchor" href="#chat" aria-label="Permalink to &quot;Chat&quot;">​</a></h1><h2 id="sending-messages" tabindex="-1">Sending Messages <a class="header-anchor" href="#sending-messages" aria-label="Permalink to &quot;Sending Messages&quot;">​</a></h2><p>Type in the input box and press <strong>Enter</strong> to send. Use <strong>Shift+Enter</strong> for a newline. Press <strong>Escape</strong> to stop generation mid-stream.</p><h2 id="streaming" tabindex="-1">Streaming <a class="header-anchor" href="#streaming" aria-label="Permalink to &quot;Streaming&quot;">​</a></h2><p>Tokens render as they arrive. Markdown, code blocks, tables, and math (LaTeX via KaTeX) are rendered live. A blinking cursor indicates active generation.</p><h2 id="thinking-blocks" tabindex="-1">Thinking Blocks <a class="header-anchor" href="#thinking-blocks" aria-label="Permalink to &quot;Thinking Blocks&quot;">​</a></h2><p>Models that expose chain-of-thought reasoning (e.g. DeepSeek-R1) wrap their internal reasoning in <code>&amp;lt;think&amp;gt;</code> tags. Alpaka Desktop detects these automatically and renders them in a collapsible panel with a pulsing border while the model is still thinking.</p><ul><li>Click the panel header to collapse or expand at any time — including while the model is still thinking.</li><li>The final response appears below the thinking block.</li></ul><h2 id="attachments" tabindex="-1">Attachments <a class="header-anchor" href="#attachments" aria-label="Permalink to &quot;Attachments&quot;">​</a></h2><p>Attach files to your message using the paperclip button or by dragging and dropping onto the input area.</p><table tabindex="0"><thead><tr><th>Type</th><th>How to attach</th><th>Notes</th></tr></thead><tbody><tr><td>Images</td><td>Drag-drop, paste (<code>Ctrl+V</code>), or file picker</td><td>Vision models only (e.g. LLaVA, Gemma 3)</td></tr><tr><td>Text files</td><td>Drag-drop or file picker</td><td>Content is included in the prompt</td></tr><tr><td>PDFs</td><td>Drag-drop or file picker</td><td>Text is extracted and included</td></tr></tbody></table><p>A thumbnail preview appears in the input area before sending. Click the × to remove an attachment.</p><h2 id="web-search" tabindex="-1">Web Search <a class="header-anchor" href="#web-search" aria-label="Permalink to &quot;Web Search&quot;">​</a></h2><p>When web search is enabled (toggle in the Advanced Options panel), Alpaka Desktop uses Ollama&#39;s built-in Web Search tool call. The model can request searches during generation; results appear as collapsible cards in the chat.</p><h2 id="chat-history" tabindex="-1">Chat History <a class="header-anchor" href="#chat-history" aria-label="Permalink to &quot;Chat History&quot;">​</a></h2><p>All conversations are saved automatically to a local SQLite database.</p><table tabindex="0"><thead><tr><th>Action</th><th>How</th></tr></thead><tbody><tr><td>Search conversations</td><td><code>Ctrl+K</code> or the search icon in the sidebar</td></tr><tr><td>Rename</td><td>Right-click a conversation in the sidebar</td></tr><tr><td>Pin</td><td>Right-click → Pin to keep at the top</td></tr><tr><td>Delete</td><td>Right-click → Delete</td></tr><tr><td>Export</td><td>Three-dot menu → Export as Markdown / JSON</td></tr></tbody></table><h2 id="compact-twm-mode" tabindex="-1">Compact / TWM Mode <a class="header-anchor" href="#compact-twm-mode" aria-label="Permalink to &quot;Compact / TWM Mode&quot;">​</a></h2><p>For tiling window manager users (Hyprland, Sway, i3), Compact Mode reduces padding and hides the sidebar to make the app usable at narrow widths (min ~320px). Toggle with <code>Ctrl+Shift+M</code>.</p><p>See <a href="/alpaka-desktop/guide/keyboard">Keyboard Shortcuts</a> for all shortcuts.</p>',20)])])}const m=e(o,[["render",n]]);export{g as __pageData,m as default};
